INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='nars'),7,'Natural Radiant Longwear Foundation','nars-natural-radiant-foundation','Buildable medium-to-full coverage with 16-hour wear.','Infused with hyaluronic acid and light-diffusing pigments, this weightless formula blurs imperfections while maintaining a natural radiant finish. Builds from medium to full coverage without looking cakey.',50.00,'NARS-FDN-001',80,true,true,ARRAY['foundation','longwear','radiant','nars']),
((SELECT id FROM brands WHERE slug='mac'),7,'Studio Fix Fluid SPF 15 Foundation','mac-studio-fix-fluid-spf','Full-coverage matte foundation with built-in SPF 15.','This iconic MAC formula delivers full, buildable coverage with a natural matte finish. SPF 15 protects skin while the long-wearing formula keeps you photo-ready all day. Available in 68 shades.',40.00,'MAC-FDN-STF',90,true,false,ARRAY['foundation','matte','spf','mac','full-coverage']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),7,'Magic Foundation','ct-magic-foundation','Flawless skin-like coverage with anti-ageing technology.','Powered by Hyaluronic Acid and collagen-boosting peptides, this lightweight formula blurs pores and fine lines. Buildable from light to full coverage with a natural skin-like finish that lasts 24 hours.',55.00,'CT-FDN-MAG',75,true,true,ARRAY['foundation','anti-ageing','charlotte-tilbury','hyaluronic-acid']),
((SELECT id FROM brands WHERE slug='dior-beauty'),7,'Forever Skin Glow Foundation','dior-forever-skin-glow','24-hour wear with a luminous skin-like glow.','Dior Forever Skin Glow delivers an undetectable second-skin effect with a healthy, lit-from-within radiance. Enriched with flower wax and hyaluronic acid for plumped, glowing skin all day.',59.00,'DIOR-FDN-FSG',70,true,true,ARRAY['foundation','glow','dior','radiant','24hr']),
((SELECT id FROM brands WHERE slug='ysl-beauty'),7,'All Hours Foundation','ysl-all-hours-foundation','24-hour coverage that adapts to any condition.','YSL All Hours foundation resists heat, humidity, sweat and micro-expressions for flawless 24-hour wear. Its Transfer-Proof formula provides a medium buildable coverage with a natural matte finish.',57.00,'YSL-FDN-AH',65,true,true,ARRAY['foundation','ysl','24hr','transfer-proof','matte'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='nars'),7,'Radiant Creamy Concealer','nars-radiant-creamy-concealer','Creamy full-coverage concealer with a luminous finish.','This cult-favourite concealer provides full, buildable coverage with a naturally radiant, non-creasing finish. The hydrating formula blurs dark circles, redness and blemishes without settling into fine lines.',32.00,'NARS-CON-RCC',120,true,true,ARRAY['concealer','radiant','nars','full-coverage','hydrating']),
((SELECT id FROM brands WHERE slug='urban-decay'),7,'Naked Skin Weightless Complete Coverage Concealer','ud-naked-skin-concealer','Weightless full-coverage that looks like skin.','Urban Decay Naked Skin concealer delivers flawless full coverage while feeling completely weightless. The buildable formula blends seamlessly and won''t settle into fine lines or crease throughout the day.',30.00,'UD-CON-NSK',100,true,false,ARRAY['concealer','urban-decay','weightless','naked']),
((SELECT id FROM brands WHERE slug='tarte'),7,'Shape Tape Full Coverage Concealer','tarte-shape-tape-concealer','The #1 concealer — 24-hour full coverage.','Tarte''s iconic Shape Tape formula provides extreme full coverage with a matte finish that contours, covers and brightens. Infused with shea butter and licorice root, it''s long-wearing and crease-resistant.',29.00,'TARTE-CON-ST',150,true,true,ARRAY['concealer','tarte','full-coverage','matte','shape-tape']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),7,'Magic Away Concealer','ct-magic-away-concealer','Instant dark-circle erasing and complexion perfecting.','Charlotte Tilbury''s Magic Away concealer uses clever colour-correcting pigments to cancel out dark circles, redness and blemishes. The creamy texture blends effortlessly to a natural skin-finish with up to 24-hour wear.',36.00,'CT-CON-MAW',85,true,false,ARRAY['concealer','charlotte-tilbury','dark-circles','hydrating'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='urban-decay'),6,'Naked3 Eyeshadow Palette','ud-naked3-palette','12 rose-toned neutrals from shimmer to matte.','The Naked3 palette features 12 rose-hued neutrals ranging from pale pink shimmer to deep burgundy matte. Each shade is packed with Ultra Definition pigment for intense colour payoff with just one swipe.',54.00,'UD-EYE-NK3',60,true,true,ARRAY['eyeshadow','palette','urban-decay','naked','rose','neutral']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),6,'Luxury Palette Pillow Talk','ct-luxury-pillow-talk','8 dreamy rose-gold nudes — Charlotte''s iconic Pillow Talk shades.','The iconic Pillow Talk palette from Charlotte Tilbury contains 8 universally flattering rose-gold and nude shades. From satin to glitter and matte, this versatile palette creates both daytime and dramatic evening looks.',75.00,'CT-EYE-PLT',50,true,true,ARRAY['eyeshadow','palette','pillow-talk','charlotte-tilbury','rose-gold']),
((SELECT id FROM brands WHERE slug='too-faced'),6,'Sweet Peach Eyeshadow Palette','toofaced-sweet-peach','18 warm peachy shades with a real peach scent.','Too Faced Sweet Peach features 18 shades inspired by the colours and shades of a ripe peach. The peach-scented palette includes a mix of shimmers, mattes and glitters in warm coral, gold and bronze tones.',48.00,'TF-EYE-SPC',70,true,true,ARRAY['eyeshadow','palette','too-faced','peach','warm']),
((SELECT id FROM brands WHERE slug='natasha-denona'),6,'Mini Gold Eyeshadow Palette','nd-mini-gold-palette','5 golden pigments in ND''s signature ultra-rich formula.','Natasha Denona''s Mini Gold palette delivers her legendary ultra-pigmented formula in a compact edit of 5 golden tones. Professional-grade pigments blend seamlessly for a foiled, glitter or matte gold look.',35.00,'ND-EYE-MNG',45,true,false,ARRAY['eyeshadow','palette','natasha-denona','gold','mini']),
((SELECT id FROM brands WHERE slug='huda-beauty'),6,'Rose Gold Remastered Palette','huda-rose-gold-palette','18 rose gold shades reimagined with improved formula.','Huda Beauty''s Rose Gold Remastered palette features 18 enhanced rose-gold and warm bronze shades with improved pigmentation and blendability. Includes pressed glitters, foils, mattes and shimmers.',67.00,'HB-EYE-RGR',55,true,true,ARRAY['eyeshadow','palette','huda-beauty','rose-gold','remastered']),
((SELECT id FROM brands WHERE slug='pat-mcgrath-labs'),6,'Mothership I Subliminal Palette','pgm-mothership-i','9 wearable warm neutrals — the starter Mothership.','The original Mothership palette from Pat McGrath Labs features 9 universally flattering warm neutral shades. Signature MotherFude pigment technology delivers intense, multi-dimensional colour with extraordinary blendability.',125.00,'PGM-EYE-M01',35,true,true,ARRAY['eyeshadow','palette','pat-mcgrath','mothership','neutral','luxury']),
((SELECT id FROM brands WHERE slug='mac'),6,'Smoky Eye Palette','mac-smoky-eye-palette','6 coordinated smoky shades for dramatic eye looks.','MAC''s Smoky Eye Palette contains 6 coordinated shades designed to create the perfect smoky eye. From pale champagne highlight to deep charcoal base, every shade blends seamlessly for an editorial finish.',40.00,'MAC-EYE-SMK',65,true,false,ARRAY['eyeshadow','palette','mac','smoky','dramatic'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='mac'),5,'Retro Matte Lipstick Ruby Woo','mac-ruby-woo-retro','The iconic blue-red matte — MAC''s #1 selling lipstick.','Ruby Woo is MAC''s most iconic lipstick shade — a true blue-red in a retro matte finish. The highly pigmented formula delivers intense colour in a single stroke with long-wearing, velvety-matte coverage.',22.00,'MAC-LIP-RW',200,true,true,ARRAY['lipstick','mac','ruby-woo','matte','red','iconic']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),5,'Matte Revolution Lipstick Pillow Talk','ct-matte-rev-pillow-talk','The universally flattering pink-nude that defined a generation.','Charlotte Tilbury''s Pillow Talk is the world''s most asked-about lipstick shade — a perfect pink-nude. The award-winning Matte Revolution formula delivers intense colour with a comfortable, non-drying wear.',38.00,'CT-LIP-PTMT',180,true,true,ARRAY['lipstick','pillow-talk','charlotte-tilbury','matte','nude','pink']),
((SELECT id FROM brands WHERE slug='nars'),5,'Audacious Lipstick','nars-audacious-lipstick','Saturated colour with a comfortable semi-matte finish.','NARS Audacious Lipstick delivers 10 hours of saturated pigment-rich colour in a comfortable semi-matte finish. The creamy formula glides on effortlessly and keeps lips moisturised throughout wear.',40.00,'NARS-LIP-AUD',90,true,true,ARRAY['lipstick','nars','audacious','semi-matte','long-wearing']),
((SELECT id FROM brands WHERE slug='ysl-beauty'),5,'Rouge Pur Couture The Bold Lipstick','ysl-rouge-pur-couture-bold2','Intense 80% pigment-loaded lipstick with a demi-matte finish.','YSL''s most pigment-loaded lipstick delivers 80% pure color concentration in one bold swipe. The demi-matte finish provides high-impact coverage that''s comfortable to wear all day long.',43.00,'YSL-LIP-RPB',85,true,true,ARRAY['lipstick','ysl','bold','demi-matte','high-pigment']),
((SELECT id FROM brands WHERE slug='dior-beauty'),5,'Rouge Dior Couture Lipstick','dior-rouge-dior-couture','Iconic Dior couture lipstick in a new refillable case.','The iconic Rouge Dior in a luxurious refillable couture cannage-engraved case. This collector''s lipstick delivers intense, long-wearing colour in four finishes: satin, matte, metallic and velvet.',44.00,'DIOR-LIP-RDC',75,true,true,ARRAY['lipstick','dior','couture','refillable','luxury']),
((SELECT id FROM brands WHERE slug='givenchy'),5,'Le Rouge Deep Velvet Lipstick','givenchy-le-rouge-velvet','Extreme matte pigment with a velvety powdery texture.','Givenchy Le Rouge Deep Velvet features 90% pigment concentration for an extreme matte finish with a unique powdery velvet texture. The ultra-comfortable formula delivers intense coverage without drying.',42.00,'GIV-LIP-LRV',65,true,true,ARRAY['lipstick','givenchy','velvet','matte','deep-pigment']),
((SELECT id FROM brands WHERE slug='fenty-beauty'),5,'Stunna Lip Paint Longwear Fluid Lip Color','fenty-stunna-lip-paint','One-coat full coverage fluid lip colour with 12-hour wear.','Fenty Beauty Stunna Lip Paint delivers full-coverage, long-wearing colour in a lightweight fluid formula. Dries down to a comfortable matte and resists eating and drinking for up to 12 hours.',26.00,'FB-LIP-SLP',110,true,true,ARRAY['lip-color','fenty','stunna','matte','long-wearing','fluid'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),5,'Lip Cheat Lip Liner Pillow Talk','ct-lip-cheat-liner','The perfect liner to define and overline in Pillow Talk pink-nude.','Charlotte Tilbury Lip Cheat is a creamy, long-lasting lip liner that defines, overlines and perfects the lip shape. The Pillow Talk shade is a universally flattering pink-nude that pairs perfectly with any lipstick.',26.00,'CT-LNR-LCH',120,true,true,ARRAY['lip-liner','charlotte-tilbury','pillow-talk','define'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='lancome'),6,'Hypnôse Drama Mascara','lancome-hypnose-drama','Extreme volume with a bold dramatic brush.','Lancôme Hypnôse Drama features a voluminous bristle brush that grabs every lash from root to tip for 8x more volume. The buildable formula creates dramatically fanned-out lashes without clumping or flaking.',30.00,'LAN-MAS-HYP',85,true,false,ARRAY['mascara','lancome','volume','dramatic']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),6,'Pillow Talk Push Up Lashes Mascara','ct-pillow-talk-mascara','Lift, volume and length — the ultimate Pillow Talk lash.','Charlotte Tilbury Pillow Talk Push Up Lashes creates the ultimate Pillow Talk lash look: lifted, volumised and lengthened. The patent-pending Push-Up Wand lifts from the root to create an eye-opening effect.',32.00,'CT-MAS-PTL',90,true,true,ARRAY['mascara','charlotte-tilbury','pillow-talk','lift','volume']),
((SELECT id FROM brands WHERE slug='maybelline'),6,'Sky High Mascara','maybelline-sky-high','Limitless length and a feathery soft finish.','Maybelline Sky High mascara uses Flex Tower brush technology to reach every lash and build limitless length. The lightweight formula extends without smudging, clumping or weighing lashes down.',12.00,'MAY-MAS-SKH',300,true,true,ARRAY['mascara','maybelline','lengthening','drugstore','sky-high']),
((SELECT id FROM brands WHERE slug='dior-beauty'),6,'Diorshow Pump N Volume Mascara','dior-diorshow-pump','Pump for maximum volume with a flexible cushion brush.','Diorshow Pump N Volume features a revolutionary pump mechanism that charges the formula for maximum volume. The soft cushion brush separates and fans out each lash for a full, theatrical volume effect.',33.00,'DIOR-MAS-PNV',70,true,false,ARRAY['mascara','dior','diorshow','volume','pump']),
((SELECT id FROM brands WHERE slug='too-faced'),6,'Better Than Sex Mascara','toofaced-better-than-sex','Dramatic volume and length — the original cult mascara.','Too Faced Better Than Sex mascara is formulated with collagen and hyaluronic acid for dramatically voluminous, lengthened lashes. The hourglass-shaped brush wraps every lash from root to tip.',29.00,'TF-MAS-BTS',140,true,true,ARRAY['mascara','too-faced','volume','length','cult']),
((SELECT id FROM brands WHERE slug='ysl-beauty'),6,'Mascara Volume Effet Faux Cils','ysl-mascara-volume-faux-cils','Intense false-lash effect volume in a single coat.','YSL''s legendary Mascara Volume Effet Faux Cils delivers a false-lash effect from the very first coat. The thick, rich formula coats each lash evenly for a dramatically volumised, fanned-out finish.',35.00,'YSL-MAS-VEF',75,true,false,ARRAY['mascara','ysl','volume','false-lash'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='nars'),7,'Orgasm Blush','nars-orgasm-blush','The world''s most famous blush — a peachy-pink with gold shimmer.','NARS Orgasm is the iconic universally flattering peachy-pink blush with gold shimmer. The finely milled powder formula delivers a natural healthy flush with a luminous golden highlight that suits every skin tone.',34.00,'NARS-BLU-ORG',160,true,true,ARRAY['blush','nars','orgasm','shimmer','peachy-pink','iconic']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),7,'Cheek to Chic Blush Pillow Talk','ct-cheek-to-chic-pillow-talk','Sculpting blush duo in the iconic Pillow Talk shades.','Charlotte Tilbury Cheek to Chic features a two-tone blush duo — a lighter highlight shade and deeper flush shade — to sculpt and define cheekbones. The Pillow Talk shades are universally flattering for all skin tones.',45.00,'CT-BLU-CTC',70,true,true,ARRAY['blush','charlotte-tilbury','pillow-talk','sculpting','duo']),
((SELECT id FROM brands WHERE slug='benefit'),7,'Hoola Matte Bronzer','benefit-hoola-bronzer','The original matte bronzer for a natural sun-kissed glow.','Benefit Hoola is the original talc-free matte bronzer that gives a natural sun-kissed glow without shimmer. The finely milled formula applies evenly and blends beautifully for a seamless, buildable colour.',36.00,'BEN-BRZ-HOO',130,true,true,ARRAY['bronzer','benefit','hoola','matte','natural','sun-kissed']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),7,'Filmstar Bronze & Glow','ct-filmstar-bronze-glow','Sculpting bronzer and highlighter duo for a Hollywood finish.','Charlotte Tilbury Filmstar Bronze & Glow is the ultimate Hollywood contouring duo. The warm bronze and champagne highlight work together to sculpt cheekbones and add a luminous, film-star glow.',70.00,'CT-BRZ-FBG',65,true,true,ARRAY['bronzer','highlighter','charlotte-tilbury','sculpting','hollywood']),
((SELECT id FROM brands WHERE slug='fenty-beauty'),7,'Killawatt Freestyle Highlighter','fenty-killawatt-highlighter','Metallic highlight that hits from any angle.','Fenty Beauty Killawatt delivers a blinding metallic highlight with an ultra-fine milled formula. The innovative compact houses two coordinating shades that can be used separately or swirled together for a custom glow.',40.00,'FB-HLT-KLW',85,true,true,ARRAY['highlighter','fenty','killawatt','metallic','glow']),
((SELECT id FROM brands WHERE slug='becca'),7,'Shimmering Skin Perfector Pressed Highlighter','becca-shimmering-skin-perfector','The cult liquid-like highlight in a pressed compact.','Becca Shimmering Skin Perfector Pressed delivers the brand''s iconic liquid-like highlight in a convenient pressed format. The ultra-finely milled formula melts into skin for a seamless, glassy, lit-from-within glow.',38.00,'BEC-HLT-SSP',90,true,false,ARRAY['highlighter','becca','shimmer','pressed','glow'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='urban-decay'),7,'All Nighter Long-Lasting Makeup Setting Spray','ud-all-nighter-spray','16-hour makeup setting spray with temperature control technology.','Urban Decay All Nighter uses Temperature Control Technology to keep makeup in place for up to 16 hours through heat, humidity and sweat. A fine mist locks in colour while maintaining a natural, non-sticky finish.',34.00,'UD-SET-ANS',120,true,true,ARRAY['setting-spray','urban-decay','all-nighter','long-wearing','16hr']),
((SELECT id FROM brands WHERE slug='smashbox'),7,'Photo Finish Foundation Primer','smashbox-photo-finish-primer','The original photo-perfecting primer — blurs pores and fine lines.','Smashbox Photo Finish is the original primer trusted by professional makeup artists worldwide. The silky, lightweight formula instantly blurs pores, fine lines and uneven texture for a smooth, airbrushed canvas.',42.00,'SBX-PRI-PFF',100,true,true,ARRAY['primer','smashbox','photo-finish','pore-blurring','original']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),7,'Magic Primer','ct-magic-primer','Primes, hydrates and perfects for flawless makeup application.','Charlotte Tilbury Magic Primer uses hyaluronic acid and skin-smoothing technology to create the ultimate base for makeup. It fills fine lines, blurs pores and extends makeup wear while keeping skin hydrated throughout the day.',45.00,'CT-PRI-MAG',75,true,false,ARRAY['primer','charlotte-tilbury','magic','hydrating','smoothing']),
((SELECT id FROM brands WHERE slug='laura-mercier'),7,'Translucent Loose Setting Powder','laura-mercier-translucent-powder','The #1 setting powder — translucent, weightless, flawless.','Laura Mercier Translucent Loose Setting Powder is the iconic setting powder trusted by makeup artists for decades. The ultra-fine, weightless formula sets makeup, controls shine and blurs imperfections for a flawless finish.',42.00,'LM-POW-TLS',180,true,true,ARRAY['setting-powder','laura-mercier','translucent','setting','classic'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='anastasia-bh'),6,'Brow Wiz Micro-Stroke Eyebrow Pencil','abh-brow-wiz','Ultra-fine micro-stroke pencil for hair-like brow strokes.','ABH Brow Wiz features an ultra-thin retractable tip that mimics the look of real brow hairs with precise, micro-stroked strokes. The spoolie on the end blends for a perfectly natural, defined brow.',24.00,'ABH-BRW-BWZ',200,true,true,ARRAY['eyebrow','anastasia-bh','brow-wiz','pencil','micro-stroke']),
((SELECT id FROM brands WHERE slug='benefit'),6,'Precisely My Brow Pencil','benefit-precisely-brow','Ultra-fine precision brow pencil for natural-looking fullness.','Benefit Precisely My Brow is an ultra-fine brow pencil with a tip just 1mm wide. The waxy formula deposits pigment precisely to fill, define and shape brows for a naturally full, polished look.',24.00,'BEN-BRW-PMB',150,true,false,ARRAY['eyebrow','benefit','pencil','precision','define']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),6,'Brow Lift','ct-brow-lift','Clear brow sculpting wax lifts and sets brows all day.','Charlotte Tilbury Brow Lift uses a clear sculpting wax to lift, set and define brows in a natural, brushed-up style. The buildable formula can be used with or over brow products for a polished, elevated brow arch.',30.00,'CT-BRW-BLF',80,true,false,ARRAY['eyebrow','charlotte-tilbury','brow-lift','setting','clear'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='urban-decay'),6,'24/7 Glide-On Eye Pencil','ud-247-glide-on-pencil','Smudge-proof eyeliner with 24-hour wear.','Urban Decay 24/7 Glide-On Eye Pencil glides on effortlessly for intense colour with up to 24-hour wear. The waterproof, smudge-proof formula is infused with jojoba oil and vitamin E for a comfortable application.',22.00,'UD-ELN-247',130,true,false,ARRAY['eyeliner','urban-decay','pencil','24hr','waterproof']),
((SELECT id FROM brands WHERE slug='stila'),6,'Stay All Day Waterproof Liquid Eyeliner','stila-stay-all-day-liner','Ultra-fine liquid liner with 12-hour stay-all-day formula.','Stila Stay All Day delivers precision liquid liner in one smooth stroke. The advanced micro-tip felt applicator creates lines from ultra-thin to bold, with a waterproof formula that truly stays all day without smudging.',22.00,'STI-ELN-SAD',110,true,false,ARRAY['eyeliner','stila','liquid','waterproof','precision','wing']),
((SELECT id FROM brands WHERE slug='mac'),6,'Fluidline Eye Liner Gel','mac-fluidline-gel-liner','Professional-grade gel liner for precise, long-lasting lines.','MAC Fluidline is the professional makeup artist''s gel eyeliner of choice. The smooth, creamy gel formula applies easily with a brush for intense colour that dries quickly and resists smudging for up to 12 hours.',22.00,'MAC-ELN-FLL',100,true,false,ARRAY['eyeliner','mac','gel','professional','long-wearing']),
((SELECT id FROM brands WHERE slug='lancome'),6,'Le Stylo Waterproof Long Lasting Eyeliner','lancome-le-stylo-eyeliner','Smooth retractable pencil with a built-in smudger tip.','Lancôme Le Stylo is a retractable kohl-like pencil that delivers rich, creamy colour in one stroke. The waterproof formula has 24-hour wear and the built-in smudge tip creates a soft smoky effect at the flip of the pencil.',26.00,'LAN-ELN-LST',90,true,false,ARRAY['eyeliner','lancome','pencil','waterproof','smudger'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='sigma-beauty'),14,'F80 Flat Kabuki Brush','sigma-f80-kabuki','Dense flat-top kabuki for airbrushed liquid foundation.','Sigma F80 uses SigmaTech fibres to buff liquid and powder foundation into skin with zero streaks. The dense, flat-top dome delivers full coverage with a flawless, airbrushed finish.',34.00,'SIG-BRU-F80',80,true,true,ARRAY['brush','foundation-brush','sigma','kabuki','flat-top']),
((SELECT id FROM brands WHERE slug='real-techniques'),14,'Expert Face Brush','rt-expert-face-brush','Flat foundation brush for seamless coverage.','Real Techniques Expert Face Brush features ultra-plush synthetic bristles that pick up the right amount of product and blend it seamlessly into skin. Flat-cut head allows for precise application from cheeks to nose.',10.00,'RT-BRU-EFB',200,true,false,ARRAY['brush','foundation-brush','real-techniques','affordable']),
((SELECT id FROM brands WHERE slug='morphe'),14,'M439 Deluxe Buffer Brush','morphe-m439-buffer','Full-dome buffer brush for blending and buffing.','Morphe M439 is an oversized dome brush with super-soft Taklon fibres for buffing foundation, powder or blush with a seamless finish. The full dome shape covers large areas quickly.',18.00,'MPH-BRU-M439',90,true,false,ARRAY['brush','buffer','morphe','foundation','blush']),
((SELECT id FROM brands WHERE slug='sigma-beauty'),14,'F35 Tapered Highlighter Brush','sigma-f35-highlighter','Tapered fan-dome for precise highlighter placement.','Sigma F35 Tapered Highlighter Brush uses a gently domed, tapered shape to place and blend highlighter precisely on cheekbone peaks, brow bones and the bridge of the nose.',26.00,'SIG-BRU-F35',70,true,false,ARRAY['brush','highlighter','sigma','tapered','contour']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),14,'Powder & Sculpt Brush','ct-powder-sculpt-brush','Dual-ended powder and contouring brush.','Charlotte Tilbury Powder & Sculpt Brush features two ends — a full dome for setting powder and a tapered angled end for precise contouring and bronzing. Premium natural and synthetic blend bristles.',60.00,'CT-BRU-PSB',40,true,false,ARRAY['brush','powder','sculpt','charlotte-tilbury','dual-ended']),
((SELECT id FROM brands WHERE slug='tom-ford-beauty'),14,'Powder Brush 01','tomford-powder-brush-01','Ultra-luxe powder brush with the finest natural hair.','Tom Ford Powder Brush 01 features the most exquisite natural hair bristles housed in a polished chrome and black lacquer handle. Buffs loose and pressed powder to a seamless, flawless finish.',90.00,'TF-BRU-PB01',25,true,true,ARRAY['brush','powder','tom-ford','luxury','natural-hair']),
((SELECT id FROM brands WHERE slug='bobbi-brown'),14,'Face Blender Brush','bobbi-face-blender-brush','Rounded face brush for blending and buffing.','Bobbi Brown Face Blender Brush is a full, rounded brush designed to blend foundation, concealer and powder seamlessly. Premium synthetic fibres pick up and distribute product evenly across the face.',48.00,'BB-BRU-FBL',50,true,false,ARRAY['brush','blender','bobbi-brown','foundation','blending']),
((SELECT id FROM brands WHERE slug='it-cosmetics'),14,'Heavenly Luxe Flat Top Buffing Foundation Brush #6','itc-heavenly-luxe-buffer','Heavenly Luxe flat-top brush for full-coverage buffing.','IT Cosmetics Heavenly Luxe #6 uses anti-bacterial, extra-soft fibres that do not absorb product. The flat-top dome buffs liquid, cream and powder foundation to a flawless, full-coverage airbrushed finish.',48.00,'ITC-BRU-HL6',55,true,false,ARRAY['brush','foundation','it-cosmetics','flat-top','buffing']),
((SELECT id FROM brands WHERE slug='mac'),14,'170 Synthetic Rounded Slant Brush','mac-170-slant-brush','Synthetic rounded slant for blush, bronzer and contouring.','MAC 170 Synthetic Rounded Slant Brush has a unique rounded, slanted shape that hugs the cheekbone for precise blush and bronzer placement. The synthetic bristles work beautifully with both powder and cream products.',38.00,'MAC-BRU-170',65,true,false,ARRAY['brush','contour','mac','slant','blush']),
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='fenty-beauty'),(SELECT id FROM categories WHERE slug='accessories'),'Precision Makeup Sponge','fenty-precision-sponge','Tapered precision sponge for foundation and concealer.','Fenty Beauty Precision Makeup Sponge is tapered on both ends for targeted application. The pointed tip applies concealer and spot coverage precisely while the rounded end blends foundation seamlessly.',20.00,'FB-SPG-PMS',100,true,false,ARRAY['sponge','fenty','precision','blending']),
((SELECT id FROM brands WHERE slug='real-techniques'),(SELECT id FROM categories WHERE slug='accessories'),'Miracle Complexion Sponge','rt-miracle-sponge','Unique shape for seamless full-face blending at an unbeatable price.','Real Techniques Miracle Complexion Sponge features a unique flat edge and rounded sides that blend foundation seamlessly across the face. The pointed tip reaches the corners of the nose and under eyes.',8.00,'RT-SPG-MCS',250,true,true,ARRAY['sponge','real-techniques','affordable','blending','miracle']),
((SELECT id FROM brands WHERE slug='it-cosmetics'),14,'Heavenly Skin Smoothing Complexion Brush 702','itc-702-complexion-brush','Paddle complexion brush for smoothing and setting.','IT Cosmetics 702 Brush uses Heavenly Luxe anti-bacterial fibres to smooth, blend and set makeup over the entire face. The paddle shape covers large areas quickly for a perfectly blended base.',48.00,'ITC-BRU-702',45,true,false,ARRAY['brush','complexion','it-cosmetics','smoothing','702']),
((SELECT id FROM brands WHERE slug='shiseido'),(SELECT id FROM categories WHERE slug='accessories'),'Eyelash Curler','shiseido-eyelash-curler','Salon-quality lash curler with precise jaw alignment.','Shiseido Eyelash Curler is a professional-grade lash curler with a precisely aligned jaw that grasps all lashes from corner to corner. The ergonomic design provides consistent curl without pinching.',22.00,'SHI-TOO-ELC',90,true,false,ARRAY['eyelash-curler','shiseido','professional','lashes']),
((SELECT id FROM brands WHERE slug='shu-uemura'),(SELECT id FROM categories WHERE slug='accessories'),'S Curler Eyelash Curler','shu-uemura-s-curler','The definitive professional eyelash curler used by top artists.','Shu Uemura S Curler is the global gold standard in eyelash curling — used by professional makeup artists worldwide. The signature S-shaped design creates a natural, long-lasting curl that opens up the eyes.',22.00,'SHU-TOO-SCR',75,true,true,ARRAY['eyelash-curler','shu-uemura','professional','cult']),
((SELECT id FROM brands WHERE slug='charlotte-tilbury'),(SELECT id FROM categories WHERE slug='accessories'),'Mesh Eyelash Curler','ct-mesh-eyelash-curler','Gentle mesh-padded curler for a natural lifted curl.','Charlotte Tilbury Mesh Eyelash Curler features a unique mesh pad design that curls lashes gently without crimping. The ergonomic handle provides precise control for a naturally lifted curl every time.',26.00,'CT-TOO-MEC',60,true,false,ARRAY['eyelash-curler','charlotte-tilbury','gentle','mesh']),
((SELECT id FROM brands WHERE slug='tweezerman'),(SELECT id FROM categories WHERE slug='accessories'),'Classic Slant Tweezer','tweezerman-slant','Stainless steel hand-filed slant tweezers — the world''s best.','Tweezerman Classic Slant Tweezers are hand-filed to a perfect slant tip that grabs every hair — even the finest — on the first try. Stainless steel construction ensures precision and longevity.',28.00,'TWZ-TOO-CST',150,true,true,ARRAY['tweezer','tweezerman','slant','professional','stainless']),
((SELECT id FROM brands WHERE slug='anastasia-bh'),14,'Dual-Ended Precision Brush 7B','abh-dual-ended-brush-7b','Dual-ended brow and liner brush for precision detailing.','ABH Dual-Ended Precision Brush 7B features a flat angled end for applying brow powder or gel and a fine liner end for detailed brow hair strokes. Essential for perfecting brow shape.',18.00,'ABH-BRU-7B',85,true,false,ARRAY['brow-brush','anastasia-bh','dual-ended','precision']),
((SELECT id FROM brands WHERE slug='benefit'),(SELECT id FROM categories WHERE slug='accessories'),'Gimme Brow+ Volumizing Eyebrow Gel','benefit-gimme-brow','Tinted volumizing gel for fuller, natural-looking brows.','Benefit Gimme Brow+ is a tinted, volumizing brow gel with tiny microfibers that adhere to skin and hair to visibly fill in brows. The buildable formula creates natural-looking fullness that lasts all day.',26.00,'BEN-BRW-GMB',140,true,true,ARRAY['brow-gel','benefit','volumizing','tinted','natural']),
((SELECT id FROM brands WHERE slug='simplehuman'),(SELECT id FROM categories WHERE slug='accessories'),'8" Sensor Mirror Pro','simplehuman-sensor-mirror-pro','Sensor-activated 5x magnification vanity mirror.','Simplehuman 8" Sensor Mirror Pro auto-activates when your face is near and delivers the truest, most natural light of any vanity mirror. Tru-lux light technology simulates natural sunlight for flawless makeup application.',249.00,'SHU-MIR-SMP',20,true,true,ARRAY['mirror','simplehuman','sensor','magnification','vanity']),
((SELECT id FROM brands WHERE slug='fancii'),(SELECT id FROM categories WHERE slug='accessories'),'Vanity Mirror with LED Lights','fancii-led-vanity-mirror','Hollywood-style LED vanity mirror with 3 light settings.','Fancii Vanity Mirror features 21 dimmable LED lights across 3 colour modes (daylight, natural, warm) for perfect makeup application in any lighting. The 1x/5x dual-sided magnification suits all tasks.',70.00,'FAN-MIR-VLM',40,true,false,ARRAY['mirror','fancii','led','vanity','hollywood']),
((SELECT id FROM brands WHERE slug='muji'),(SELECT id FROM categories WHERE slug='accessories'),'Acrylic Cosmetics Case','muji-acrylic-case','Minimalist acrylic organiser for brushes and products.','Muji Acrylic Cosmetics Case keeps makeup tidy in a clean, minimalist design. The transparent acrylic construction makes contents instantly visible while the neutral design suits any vanity setup.',38.00,'MUJ-ORG-ACC',60,true,false,ARRAY['organizer','muji','acrylic','storage','minimalist']),
((SELECT id FROM brands WHERE slug='foreo'),(SELECT id FROM categories WHERE slug='devices')),'LUNA 4 Facial Cleansing Brush','foreo-luna-4','Next-generation T-Sonic cleansing for all skin types.','FOREO LUNA 4 uses upgraded T-Sonic pulsations and ultra-hygienic silicone touchpoints to deeply cleanse pores and remove 99.5% of dirt, oil and makeup residue. 16 intensity levels for a personalised cleanse.',199.00,'FOR-DEV-L4',30,true,true,ARRAY['cleansing','foreo','luna','device','sonic','facial']),
((SELECT id FROM brands WHERE slug='clarisonic'),(SELECT id FROM categories WHERE slug='devices')),'Mia Smart Sonic Facial Cleansing Device','clarisonic-mia-smart','Smart sonic cleansing device with app connectivity.','Clarisonic Mia Smart delivers 300 micro-movements per second to remove 6x more makeup and 99% more dirt than manual cleansing. App-connected for personalised cleansing routines and timer.',149.00,'CLA-DEV-MIA',35,true,true,ARRAY['cleansing','clarisonic','mia','device','sonic']),
((SELECT id FROM brands WHERE slug='real-techniques'),(SELECT id FROM categories WHERE slug='accessories'),'Brush Cleansing Palette','rt-brush-cleansing-palette','Silicone palette for deep-cleaning makeup brushes.','Real Techniques Brush Cleansing Palette fits in the palm of your hand and features 8 different silicone textures to deep-clean makeup brushes of all shapes and sizes. Suction cup base keeps it stable.',8.00,'RT-CLN-BCP',180,true,false,ARRAY['brush-cleaner','real-techniques','palette','silicone']),
((SELECT id FROM brands WHERE slug='beautyblender'),(SELECT id FROM categories WHERE slug='accessories'),'BlenderCleanser Pro Solid Cleanser','bb-blendercleaner-pro','Solid cleanser removes all makeup residue from sponges and brushes.','Beautyblender BlenderCleanser Pro Solid is a concentrated solid formula that removes 100% of makeup, dirt and oils from sponges and brushes. Gentle enough for daily use with no harsh chemicals.',16.00,'BB-CLN-PRS',160,true,false,ARRAY['sponge-cleaner','beautyblender','solid','cleanser','brushes'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='chanel'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Chanel No.5 Eau de Parfum','chanel-no5-edp','The world''s most iconic fragrance since 1921.','Created by Ernest Beaux for Coco Chanel in 1921, No.5 is the world''s most recognisable fragrance. A floral aldehyde with notes of ylang-ylang, rose, jasmine, vetiver and sandalwood — timeless and eternal.',95.00,'CHA-FRG-N5',60,true,true,ARRAY['fragrance','chanel','no5','floral','iconic','edp']),
((SELECT id FROM brands WHERE slug='chanel'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Coco Mademoiselle Eau de Parfum','chanel-coco-mademoiselle','Fresh, bold and sensual — a modern Chanel icon.','Coco Mademoiselle by Chanel is a luminous fresh oriental fragrance with top notes of orange and bergamot, a heart of rose and jasmine, and a warm base of patchouli, vetiver and white musk.',105.00,'CHA-FRG-CMM',55,true,true,ARRAY['fragrance','chanel','coco-mademoiselle','oriental','floral','edp']),
((SELECT id FROM brands WHERE slug='chanel'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Bleu de Chanel Eau de Parfum','chanel-bleu-de-chanel','A woody aromatic fragrance of freedom for men.','Bleu de Chanel EDP is a woody aromatic fragrance combining fresh citrus top notes with a heart of labdanum, jasmine and ginger, settling into a rich base of cedarwood, sandalwood and vetiver.',105.00,'CHA-FRG-BDC',50,true,true,ARRAY['fragrance','chanel','bleu','woody','aromatic','men']),
((SELECT id FROM brands WHERE slug='chanel'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Chance Eau Tendre Eau de Toilette','chanel-chance-tendre-edt','A fresh floral feminine — chance in its lightest form.','Chance Eau Tendre EDT opens with grapefruit and quince, blooms into a heart of hyacinth and jasmine, and rests on a base of white musk and cedarwood. Light, romantic and effortlessly chic.',100.00,'CHA-FRG-CTT',50,true,false,ARRAY['fragrance','chanel','chance','floral','fresh','edt'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='dior-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Miss Dior Eau de Parfum','dior-miss-dior-edp','A floral declaration of love — radiant peony and rose.','Miss Dior EDP is a radiant bouquet of Grasse rose absolute, peony and rosewood with a base of white musks and sensual iris. A love letter in a bottle, it embodies the modern Dior woman.',105.00,'DIOR-FRG-MDE',60,true,true,ARRAY['fragrance','dior','miss-dior','floral','rose','romantic']),
((SELECT id FROM brands WHERE slug='dior-beauty'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Sauvage Eau de Toilette','dior-sauvage-edt','A raw, noble and fresh aromatic fragrance for men.','Dior Sauvage EDT opens with a radiant burst of bergamot, deepened by a Sichuan pepper heart and grounded in a base of ambroxan for an intense, magnetic and raw masculinity.',110.00,'DIOR-FRG-SVT',65,true,true,ARRAY['fragrance','dior','sauvage','fresh','aromatic','men','bestseller']),
((SELECT id FROM brands WHERE slug='dior-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'J''adore Eau de Parfum','dior-jadore-edp','A floral absolute — the femininity of flowers in full bloom.','J''adore by Dior is a luminous floral bouquet of Damascus rose, ylang-ylang, orchid and jasmine on a base of civet, musk and blackberry. The gold bottle is as iconic as the scent itself.',105.00,'DIOR-FRG-JAD',55,true,true,ARRAY['fragrance','dior','jadore','floral','luxury','gold']),
((SELECT id FROM brands WHERE slug='dior-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Dior Homme Intense Eau de Parfum','dior-homme-intense','An intense iris-lavender woody masculinity.','Dior Homme Intense opens with lavender before revealing the signature Dior iris accord — powder, lipstick and mineral — with a base of pear tree wood and skin musk. Sophisticated and unforgettable.',120.00,'DIOR-FRG-DHI',40,true,false,ARRAY['fragrance','dior','homme','iris','lavender','men'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='ysl-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Black Opium Eau de Parfum','ysl-black-opium-edp2','The addictive coffee and vanilla-spiked floral.','YSL Black Opium EDP opens with a rush of black coffee and pink pepper, blooms into jasmine and orange blossom, and settles into a sensual base of vanilla, patchouli and cedarwood. Addictive and intoxicating.',95.00,'YSL-FRG-BOP',70,true,true,ARRAY['fragrance','ysl','black-opium','coffee','floral','sensual']),
((SELECT id FROM brands WHERE slug='ysl-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Mon Paris Eau de Parfum','ysl-mon-paris','A chypre fruity floral inspired by Parisian love.','Mon Paris by YSL is a romantic white floral fragrance with top notes of strawberry, raspberry and pear, a heart of white peony, rose and jasmine, on a base of patchouli, white musk and ambrette.',90.00,'YSL-FRG-MNP',55,true,false,ARRAY['fragrance','ysl','mon-paris','floral','fruity','romantic']),
((SELECT id FROM brands WHERE slug='ysl-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Y Eau de Parfum','ysl-y-men-edp','A fresh fougère for the ambitious modern man.','YSL Y EDP opens with sage and bergamot, unfolds into a heart of geranium and clean aromatic notes, and rests on a base of cedarwood, amberwood and ambrette. Bold, modern and assertive.',95.00,'YSL-FRG-YMN',50,true,false,ARRAY['fragrance','ysl','y','men','fresh','fougere'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='armani-beauty'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Acqua di Giò Eau de Toilette','armani-acqua-di-gio','The fresh aquatic icon — sea air, citrus and cedarwood.','Acqua di Giò by Giorgio Armani is one of the world''s best-selling masculine fragrances. Inspired by the sea, it combines fresh citrus, jasmine, persimmon and neroli over a base of patchouli and cedarwood.',80.00,'ARM-FRG-ADG',75,true,true,ARRAY['fragrance','armani','acqua-di-gio','aquatic','fresh','men','bestseller']),
((SELECT id FROM brands WHERE slug='armani-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Sì Eau de Parfum','armani-si-edp-new','A luminous chypre floral — the power of yes.','Armani Sì EDP opens with blackcurrant nectar and bergamot, blooms into a heart of rose absolute and freesia, and settles into a warm base of patchouli, vanilla and white musk. Luminous and empowering.',85.00,'ARM-FRG-SI',55,true,false,ARRAY['fragrance','armani','si','floral','chypre','feminine']),
((SELECT id FROM brands WHERE slug='guerlain'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Mon Guerlain Eau de Parfum','guerlain-mon-guerlain','A lavender and vanilla fantasy inspired by Angelina Jolie.','Mon Guerlain is a fresh gourmand lavender fragrance created in collaboration with Angelina Jolie. Bergamot and lavender accord open into a heart of jasmine, before settling into a warm vanilla and cedarwood base.',100.00,'GUE-FRG-MNG',45,true,true,ARRAY['fragrance','guerlain','lavender','vanilla','gourmand','feminine']),
((SELECT id FROM brands WHERE slug='lancome'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'La Vie Est Belle Eau de Parfum','lancome-la-vie-est-belle','Life is beautiful — an iris and patchouli gourmand.','La Vie Est Belle is Lancôme''s best-selling fragrance: a joyful gourmand of iris absolute and patchouli, with a sweet praline and vanilla base. An optimistic, indulgent scent that celebrates life.',98.00,'LAN-FRG-LVEB',70,true,true,ARRAY['fragrance','lancome','la-vie-est-belle','iris','gourmand','bestseller']),
((SELECT id FROM brands WHERE slug='lancome'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Idôle Eau de Parfum','lancome-idole-edp','A rose for a new generation — bold, free and conscious.','Lancôme Idôle is a clean, luminous rose fragrance with a heart of Grasse rose, lily of the valley and cedarwood, on a base of musk and vanilla. Sustainably sourced ingredients in a refillable bottle.',90.00,'LAN-FRG-IDL',50,true,false,ARRAY['fragrance','lancome','idole','rose','clean','sustainable'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='tom-ford-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Black Orchid Eau de Parfum','tomford-black-orchid-edp2','A luxurious and sensual oriental floral.','Tom Ford Black Orchid is a rich, dark and sensual oriental floral with top notes of black truffle and ylang-ylang, a heart of black orchid and spicy floral heart, and a base of dark chocolate, incense and sandalwood.',160.00,'TF-FRG-BOR',35,true,true,ARRAY['fragrance','tom-ford','black-orchid','oriental','luxe','dark']),
((SELECT id FROM brands WHERE slug='tom-ford-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Tobacco Vanille Eau de Parfum','tomford-tobacco-vanille','A warm, spicy tobacco and vanilla absolute.','Tom Ford Private Blend Tobacco Vanille is a rich, opulent blend of tobacco leaf, vanilla, tonka bean, dried fruit and spice. An intimate, enveloping warmth that invites the world to come closer.',195.00,'TF-FRG-TV',25,true,true,ARRAY['fragrance','tom-ford','tobacco','vanilla','private-blend','warm','spicy']),
((SELECT id FROM brands WHERE slug='tom-ford-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Lost Cherry Eau de Parfum','tomford-lost-cherry','A playful, addictive cherry and almond gourmand.','Tom Ford Lost Cherry combines tart cherry liqueur and tonka bean with black cherry, roasted tonka and bitter almond for a playfully provocative, luxuriously rich gourmand fragrance.',195.00,'TF-FRG-LC',25,true,true,ARRAY['fragrance','tom-ford','cherry','gourmand','private-blend','sweet'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='jo-malone'),(SELECT id FROM categories WHERE slug='cologne'),'Wood Sage & Sea Salt Cologne','jo-malone-wood-sage','An elemental, rugged freshness — sea air and driftwood.','Jo Malone Wood Sage & Sea Salt captures the raw beauty of the sea. Ambrette and sea salt create a cool, breezy opening, warmed by sage and cashmeran for a uniquely natural, timeless scent.',80.00,'JML-FRG-WSS',50,true,true,ARRAY['fragrance','jo-malone','wood-sage','sea-salt','fresh','cologne','unisex']),
((SELECT id FROM brands WHERE slug='jo-malone'),(SELECT id FROM categories WHERE slug='cologne'),'Peony & Blush Suede Cologne','jo-malone-peony-blush-suede','A romantic, feminine floral — peonies and warm suede.','Jo Malone Peony & Blush Suede is a quintessentially English floral. Red apple opens into a heart of peony, rose and jasmine before settling into a warm, creamy suede base. Romantic and uniquely feminine.',80.00,'JML-FRG-PBS',55,true,false,ARRAY['fragrance','jo-malone','peony','suede','floral','feminine','cologne']),
((SELECT id FROM brands WHERE slug='jo-malone'),(SELECT id FROM categories WHERE slug='cologne'),'Lime Basil & Mandarin Cologne','jo-malone-lime-basil','The original Jo Malone — zesty, herbal and iconic.','The fragrance that launched Jo Malone London — a surprisingly daring and clean fresh scent of peppery basil and thyme set against lime and mandarin. Crisp, aromatic and effortlessly elegant.',75.00,'JML-FRG-LBM',50,true,false,ARRAY['fragrance','jo-malone','lime','basil','mandarin','fresh','cologne'])
INSERT INTO products (brand_id,category_id,name,slug,short_description,description,price,sku,stock_quantity,is_active,is_featured,tags) VALUES
((SELECT id FROM brands WHERE slug='viktor-rolf'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Flowerbomb Eau de Parfum','viktor-rolf-flowerbomb','An addictive floral explosion — the modern feminine icon.','Viktor & Rolf Flowerbomb is an explosion of flowers: sambac jasmine, rose, freesia, cattleya orchid and patchouli create a rich, warm floral-oriental that is simultaneously feminine and powerfully unforgettable.',120.00,'VR-FRG-FLW',50,true,true,ARRAY['fragrance','viktor-rolf','flowerbomb','floral','oriental','bestseller']),
((SELECT id FROM brands WHERE slug='maison-margiela'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Replica By the Fireplace Eau de Toilette','mm-replica-by-fireplace','A winter memory — chestnut, vanilla and smoky embers.','Maison Margiela Replica By the Fireplace captures the warmth of crackling fire with notes of chestnut cream, smoky embers, cedarwood, guaiac wood and vanilla. A comforting, intimate memory in a bottle.',165.00,'MM-FRG-BTF',40,true,true,ARRAY['fragrance','maison-margiela','replica','fireplace','cozy','vanilla','smoke']),
((SELECT id FROM brands WHERE slug='maison-margiela'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Replica Lazy Sunday Morning Eau de Toilette','mm-replica-lazy-sunday','White musk and peony — the scent of clean, soft linens.','Maison Margiela Replica Lazy Sunday Morning captures the soft, powdery intimacy of a slow morning. White musk, peony and milk accord create a clean, comforting, skin-like scent.',155.00,'MM-FRG-LSM',35,true,false,ARRAY['fragrance','maison-margiela','replica','musk','clean','soft']),
((SELECT id FROM brands WHERE slug='hermes'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Twilly d''Hermès Eau de Parfum','hermes-twilly-edp','A young, playful and free Hermès feminine.','Hermès Twilly d''Hermès captures the spirit of youth and freedom. Ginger and tuberose dance over a base of sandalwood for a cheeky, sensual and luminous fragrance that embodies contemporary femininity.',130.00,'HER-FRG-TWL',40,true,true,ARRAY['fragrance','hermes','twilly','ginger','tuberose','feminine']),
((SELECT id FROM brands WHERE slug='hermes'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'H24 Eau de Toilette','hermes-h24-edt','A living wood fougère for the contemporary man.','Hermès H24 opens with rosewood and clary sage, deepened by a heart of narcissus and schizandra berry, on a base of cedarwood and amber wood. A bold, living interpretation of modern masculinity.',130.00,'HER-FRG-H24',35,true,false,ARRAY['fragrance','hermes','h24','woody','fougere','men']),
((SELECT id FROM brands WHERE slug='gucci'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Bloom Eau de Parfum','gucci-bloom-edp','A white floral explosion — an entire garden in full bloom.','Gucci Bloom is an intensely rich white floral composition created by Gucci Creative Director Alessandro Michele. Tuberose and Rangoon creeper bloom over a jasmine heart and a base of sandalwood.',95.00,'GUC-FRG-BLM',55,true,true,ARRAY['fragrance','gucci','bloom','floral','tuberose','jasmine']),
((SELECT id FROM brands WHERE slug='gucci'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Guilty Eau de Toilette','gucci-guilty-edt','A modern floral chypre for the fearless and the free.','Gucci Guilty EDT opens with pink pepper and mandarin orange, blooms into a heart of geranium and lilac, before settling into patchouli and amber. An unapologetic fragrance for the modern rebel.',90.00,'GUC-FRG-GLT',50,true,false,ARRAY['fragrance','gucci','guilty','floral','chypre','modern']),
((SELECT id FROM brands WHERE slug='prada'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Candy Eau de Parfum','prada-candy-edp','A sweet addictive caramel and musk — irresistibly indulgent.','Prada Candy is an indulgent oriental fragrance with notes of benzoin, white musk and caramel. Playful and refined, the scent balances a sensual, gourmand sweetness with the sophistication of Prada.',95.00,'PRA-FRG-CAN',50,true,true,ARRAY['fragrance','prada','candy','caramel','musk','gourmand','sweet']),
((SELECT id FROM brands WHERE slug='versace'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Bright Crystal Eau de Toilette','versace-bright-crystal-edt','Fresh, radiant and luminously feminine.','Versace Bright Crystal opens with pomegranate, yuzu and frosted accord, blooms into peony, magnolia and lotus flower, settling on amber, musk and mahogany. Fresh, sensual and radiantly feminine.',70.00,'VER-FRG-BRC',65,true,false,ARRAY['fragrance','versace','bright-crystal','fresh','floral','feminine']),
((SELECT id FROM brands WHERE slug='versace'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Eros Eau de Toilette','versace-eros-edt','A bold, powerfully seductive masculine fragrance.','Versace Eros opens with cool mint, green apple and lemon zest, deepens into a heart of aquatic notes, geranium and sage, and grounds in a base of tonka bean, oakmoss, cedarwood and vanilla.',75.00,'VER-FRG-ERS',60,true,false,ARRAY['fragrance','versace','eros','fresh','aquatic','men']),
((SELECT id FROM brands WHERE slug='marc-jacobs-beauty'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Daisy Eau de Toilette','marc-jacobs-daisy-edt','Fresh, young and whimsical — the daisy in full bloom.','Marc Jacobs Daisy is a fresh, joyful floral with top notes of wild strawberry and violet leaves, a heart of gardenia, violet and jasmine petals, on a base of white woods, musk and vanilla.',75.00,'MJB-FRG-DAI',60,true,true,ARRAY['fragrance','marc-jacobs','daisy','fresh','floral','young']),
((SELECT id FROM brands WHERE slug='burberry-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Her Eau de Parfum','burberry-her-edp','A British red berry floral — boldly feminine.','Burberry Her EDP opens with a vibrant British red berry accord — strawberry, cherry and blackberry — over a heart of white florals and a warm base of amber, musk and cedarwood.',90.00,'BUR-FRG-HER',50,true,true,ARRAY['fragrance','burberry','her','berry','floral','british']),
((SELECT id FROM brands WHERE slug='valentino-beauty'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Donna Born in Roma Eau de Parfum','valentino-donna-born-roma','Roman baroque femininity — jasmine and vanilla couture.','Valentino Donna Born in Roma opens with blackcurrant sorbet and bergamot, deepens into a Roman jasmine and heliotrope heart, and settles into a creamy vanilla and powdery iris base.',95.00,'VAL-FRG-DBR',45,true,true,ARRAY['fragrance','valentino','born-in-roma','jasmine','vanilla','feminine']),
((SELECT id FROM brands WHERE slug='carolina-herrera'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Good Girl Eau de Parfum','carolina-herrera-good-girl','Duality in a heel — jasmine by day, tonka by night.','Carolina Herrera Good Girl opens with almond and coffee, blooms into a heart of tuberose, jasmine sambac and jasmine, and settles on a base of tonka bean, cocoa, cacao and sandalwood. Two sides, one iconic stiletto.',100.00,'CH-FRG-GGP',50,true,true,ARRAY['fragrance','carolina-herrera','good-girl','jasmine','tonka','iconic']),
((SELECT id FROM brands WHERE slug='dolce-gabbana'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Light Blue Eau de Toilette','dg-light-blue-edt','The Mediterranean summer — the most famous fresh floral.','Dolce & Gabbana Light Blue is the quintessential summer fragrance: Sicilian cedar and apple open into a heart of bamboo, jasmine and white rose, settling on a base of cedarwood, musk and amber.',75.00,'DG-FRG-LBL',70,true,true,ARRAY['fragrance','dolce-gabbana','light-blue','fresh','floral','summer']),
((SELECT id FROM brands WHERE slug='dolce-gabbana'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'The One Eau de Parfum','dg-the-one-edp','A warm oriental for the sophisticated woman.','D&G The One opens with lychee, pear and mandarin, deepens into a heart of plum, lily, magnolia and rose, and settles into a warm base of musky woods, amber and vanilla.',90.00,'DG-FRG-TON',50,true,false,ARRAY['fragrance','dolce-gabbana','the-one','oriental','warm','feminine']),
((SELECT id FROM brands WHERE slug='thierry-mugler'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Angel Eau de Parfum','mugler-angel-edp','The original gourmand — the patchouli and chocolate icon.','Thierry Mugler Angel revolutionised perfumery with its groundbreaking gourmand notes: chocolate, praline, caramel and vanilla over a base of patchouli and cashmere wood. An icon since 1992.',100.00,'TM-FRG-ANG',55,true,true,ARRAY['fragrance','thierry-mugler','angel','gourmand','patchouli','chocolate','iconic']),
((SELECT id FROM brands WHERE slug='creed'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Aventus Eau de Parfum','creed-aventus-edp','The world''s most celebrated masculine fragrance.','Creed Aventus is an intensely masculine fragrance inspired by the strength and success of great emperors. Pineapple, bergamot and blackcurrant open into a heart of birch, patchouli and rose, on a base of oakmoss, musk and ambergris.',440.00,'CRD-FRG-AVN',15,true,true,ARRAY['fragrance','creed','aventus','masculine','premium','cult','pineapple']),
((SELECT id FROM brands WHERE slug='creed'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Silver Mountain Water Eau de Parfum','creed-silver-mountain-water','A crisp, pure alpine accord — clarity bottled.','Creed Silver Mountain Water captures the essence of the Swiss Alps with bergamot, mandarin and green tea, opening into a heart of violet and peach blossom, settling on a base of sandalwood, musk and vetiver.',415.00,'CRD-FRG-SMW',12,true,false,ARRAY['fragrance','creed','silver-mountain','fresh','alpine','clean']),
((SELECT id FROM brands WHERE slug='le-labo'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Santal 33 Eau de Parfum','le-labo-santal-33','The cult unisex sandalwood — the most recognised fragrance of a generation.','Le Labo Santal 33 has become the most recognised fragrance on the New York social scene. Sandalwood, iris, cedarwood and cardamom create a unique smoky, woody and leathery signature that is entirely addictive.',195.00,'LL-FRG-S33',20,true,true,ARRAY['fragrance','le-labo','santal','sandalwood','unisex','cult','niche']),
((SELECT id FROM brands WHERE slug='diptyque'),(SELECT id FROM categories WHERE slug='eau-de-toilette'),'Do Son Eau de Toilette','diptyque-do-son-edt','A sheer, watery tuberose — a Vietnamese memory.','Diptyque Do Son evokes the sensory memory of the Vietnamese bay of Do Son — a sheer, breezy tuberose against sea breeze and musk. Light and intimate, like skin scented by a warm coastal wind.',185.00,'DIP-FRG-DOS',20,true,false,ARRAY['fragrance','diptyque','do-son','tuberose','sheer','niche']),
((SELECT id FROM brands WHERE slug='byredo'),(SELECT id FROM categories WHERE slug='eau-de-parfum'),'Bal d''Afrique Eau de Parfum','byredo-bal-dafrique','African marigold, amber and musk — joyful and warm.','Byredo Bal d''Afrique is inspired by the art movement and musical exchanges between Paris and Africa in the 1920s. African marigold, violet and neroli bloom over a warm base of cedar, Moroccan amber and musk.',215.00,'BYR-FRG-BDA',18,true,true,ARRAY['fragrance','byredo','bal-dafrique','marigold','amber','warm','niche'])
